mapper.select:
SELECT COUNT(*) FROM tax_rates

  AND hsn_code = #{hsnCode}
  AND active = #{active}

SELECT id, product_category AS "productCategory", sub_category AS "subCategory",
       hsn_code AS "hsnCode", description
FROM tax_category_mapping

  AND product_category = #{productCategory}
  AND hsn_code = #{hsnCode}

ORDER BY product_category

SELECT id, state_code AS "stateCode", state_name AS "stateName", state_alpha AS "stateAlpha", union_territory AS "unionTerritory", active FROM tax_regions
AND state_code = #{stateCode} AND LOWER(state_name) LIKE LOWER(CONCAT('%', #{stateName}, '%')) AND union_territory = #{unionTerritory}
ORDER BY state_code

SELECT id, exemption_type AS "exemptionType", exemption_value AS "value", description,
       full_exemption AS "fullExemption", active
FROM tax_exemptions

  AND exemption_type = #{exemptionType}
  AND active = #{active}

ORDER BY exemption_type

SELECT id, order_id AS "orderId", variant_id AS "variantId", hsn_code AS "hsnCode", tax_type AS "taxType", taxable_amount AS "taxableAmount", gst_rate AS "gstRate", cgst_amount AS "cgstAmount", sgst_amount AS "sgstAmount", igst_amount AS "igstAmount", cess_amount AS "cessAmount", tcs_amount AS "tcsAmount", total_tax AS "totalTax" FROM order_tax_lines
AND order_id = #{orderId} AND tax_type = #{taxType}
ORDER BY created_time DESC
